function parseArgs(argv) {
  const args = [...argv];
  const command = args.shift();
  const opts = {
    ...DEFAULTS,
    command,
    execute: false,
    dryRun: false,
    runDir: "",
  };

  for (let i = 0; i < args.length; i += 1) {
    const arg = args[i];
    const next = () => {
      i += 1;
      if (i >= args.length) {
        throw new Error(`Missing value for ${arg}`);
      }
      return args[i];
    };

    switch (arg) {
      case "--source":
        opts.source = next();
        break;
      case "--baseline-root":
        opts.baselineRoot = next();
        break;
      case "--entire-root":
        opts.entireRoot = next();
        break;
      case "--runs-root":
        opts.runsRoot = next();
        break;
      case "--manifest":
        opts.manifest = next();
        break;
      case "--worker-model":
        opts.workerModel = next();
        break;
      case "--reviewer-model":
        opts.reviewerModel = next();
        break;
      case "--replicates":
        opts.replicates = Number.parseInt(next(), 10);
        break;
      case "--max-revisions":
        opts.maxRevisions = Number.parseInt(next(), 10);
        break;
      case "--limit":
        opts.limit = Number.parseInt(next(), 10);
        break;
      case "--run-dir":
        opts.runDir = next();
        break;
      case "--execute":
        opts.execute = true;
        break;
      case "--dry-run":
        opts.dryRun = true;
        break;
      case "-h":
      case "--help":
        console.log(usage);
        process.exit(0);
        break;
      default:
        throw new Error(`Unknown option: ${arg}`);
    }
