  if (!command || !["setup", "run", "summarize"].includes(command)) {
    throw new Error(`Unknown or missing command.\n\n${usage}`);
  }
  if (opts.execute && opts.dryRun) {
    throw new Error("Choose only one of --execute or --dry-run.");
